// // This module outputs 2899645186 when the address is high (1) and 1419000801 when the address is low (0).
module top_module(

                address,
                clock,
                reset_n,


                readdata
             )
;output  [ 31: 0] readdata;
  input            address;
  input            clock;
  input            reset_n;

  wire    [ 31: 0] readdata;

  assign readdata = address ? 1419000801 : 2899645186;

endmodule
